steps.script:
() => {
  const params = Object.fromEntries(new URLSearchParams(location.search));
  const scripts = [...document.querySelectorAll('script')];
  const srcs = scripts.map(s=>s.src).filter(Boolean);
  const inline = scripts.filter(s=>!s.src).map(s=>s.textContent||'');
  const hasMlSource = srcs.some(u=>/ml-source-capture/i.test(u));
  const hasKlaviyo = srcs.some(u=>/klaviyo/i.test(u)) || inline.some(t=>/klaviyo/i.test(t));
  const hasClarity = (typeof window.clarity!=='undefined') || srcs.some(u=>/clarity\.ms/i.test(u)) || inline.some(t=>/clarity/i.test(t));
  const forms = [...document.querySelectorAll('form')].map(f=>({
     id:f.id, cls:(f.className||'').slice(0,80),
     emailInputs:[...f.querySelectorAll('input[type=email],input[name*=email i]')].length,
     buttons:[...f.querySelectorAll('button,input[type=submit]')].length,
     hidden:[...f.querySelectorAll('input[type=hidden]')].map(i=>({name:i.name,val:(i.value||'').slice(0,80)}))
  }));
  const utmInputs=[...document.querySelectorAll('input')].filter(i=>/utm|source|channel/i.test(i.name||'')).map(i=>({name:i.name,val:(i.value||'').slice(0,80)}));
  const inlineUtmRefs = inline.filter(t=>/utm_source|ml-source|channel\s*[:=]|pinterest/i.test(t)).map(t=>t.replace(/\s+/g,' ').slice(0,240));
  let ls={},ss={};
  try{for(const k of Object.keys(localStorage)){if(/utm|source|channel|ml/i.test(k))ls[k]=(localStorage.getItem(k)||'').slice(0,100);}}catch(e){}
  try{for(const k of Object.keys(sessionStorage)){if(/utm|source|channel|ml/i.test(k))ss[k]=(sessionStorage.getItem(k)||'').slice(0,100);}}catch(e){}
  return {
    finalUrl: location.href, title: document.title,
    h1: ((document.querySelector('h1')||{}).textContent||'').trim().slice(0,120),
    bodyTextLen: document.body? document.body.innerText.length : 0,
    urlParams: params,
    renders: { hasMlSource, hasKlaviyo, hasClarity, formCount: forms.length },
    forms, utmInputs, inlineUtmRefs, lsKeys: ls, ssKeys: ss,
    scriptSrcSample: srcs.slice(0,40)
  };
}
